#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 200005
#define INF 1e18

// Define the structure for a tree node
typedef struct Node {
    int id;
    int weight;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new node
Node* createNode(int id, int weight) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->id = id;
    node->weight = weight;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the maximum cost of a correct decomposition for a subtree
double calculateMaxCost(Node* node) {
    if (node->numChildren == 0) {
        return node->weight;
    }
    double maxCost = -INF;
    for (int i = 0; i < node->numChildren; i++) {
        double childCost = calculateMaxCost(node->children[i]);
        maxCost = fmax(maxCost, childCost);
    }
    return fmax(maxCost, (node->weight + maxCost) / 2.0);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            int weight;
            scanf("%d", &weight);
            nodes[i] = createNode(i, weight);
        }
        for (int i = 0; i < N - 1; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            addChild(nodes[x - 1], nodes[y - 1]);
        }
        double maxCost = calculateMaxCost(nodes[0]);
        printf("%.6f\n", maxCost);
    }
    return 0;
}

