struct Node {
    int id;
    int weight;
    vector<Node*> children;
    Node(int id, int weight) : id(id), weight(weight) {}
};

double calculateMaxCost(Node* node) {
    if (node->children.empty()) {
        return node->weight;
    }
    double maxCost = -INF;
    for (Node* child : node->children) {
        double childCost = calculateMaxCost(child);
        maxCost = max(maxCost, childCost);
    }
    return max(maxCost, (node->weight + maxCost) / 2.0);
}

