// COMPLETE, COMPILABLE Java code
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {
    static class Node {
        int id;
        int weight;
        List<Node> children;
        Node(int id, int weight) {
            this.id = id;
            this.weight = weight;
            this.children = new ArrayList<>();
        }
    }

    public static double calculateMaxCost(Node node) {
        if (node.children.isEmpty()) {
            return node.weight;
        }
        double maxCost = Double.NEGATIVE_INFINITY;
        for (Node child : node.children) {
            double childCost = calculateMaxCost(child);
            maxCost = Math.max(maxCost, childCost);
        }
        return Math.max(maxCost, (node.weight + maxCost) / 2.0);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                int weight = scanner.nextInt();
                nodes[i] = new Node(i, weight);
            }
            for (int i = 0; i < N - 1; i++) {
                int x = scanner.nextInt() - 1;
                int y = scanner.nextInt() - 1;
                nodes[x].children.add(nodes[y]);
            }
            double maxCost = calculateMaxCost(nodes[0]);
            System.out.printf("%.6f\n", maxCost);
        }
    }
}

