function calculateMaxCost(node) {
    if (node.children.length === 0) {
        return node.weight;
    }
    let maxCost = -Infinity;
    for (let child of node.children) {
        let childCost = calculateMaxCost(child);
        maxCost = Math.max(maxCost, childCost);
    }
    return Math.max(maxCost, (node.weight + maxCost) / 2.0);
}

let T = parseInt(lines[idx++]);
